import 'package:cloud_firestore/cloud_firestore.dart';

class SeedDataService {
  final FirebaseFirestore _db = FirebaseFirestore.instance;

  Future<void> seedAllData({required Function(String) onProgress}) async {
    final categories = _getAllCategories();
    for (int i = 0; i < categories.length; i++) {
      final cat = categories[i];
      onProgress('📁 ${i + 1}/${categories.length}: ${cat['name']}');
      final catRef = await _db.collection('categories').add({
        'name': cat['name'],
        'icon': cat['icon'],
        'color': cat['color'],
        'order': i,
        'promptCount': 0,
        'createdAt': FieldValue.serverTimestamp(),
      });
      final subs = _getSubcategories(cat['name']!);
      int totalPrompts = 0;
      for (int s = 0; s < subs.length; s++) {
        final sub = subs[s];
        final subRef = await _db
            .collection('categories')
            .doc(catRef.id)
            .collection('subcategories')
            .add({
          'name': sub['name'],
          'icon': sub['icon'],
          'order': s,
          'promptCount': 0,
          'createdAt': FieldValue.serverTimestamp(),
        });
        final prompts = _getPrompts(cat['name']!, sub['name']!);
        for (final p in prompts) {
          await _db.collection('prompts').add({
            'title': p['title'],
            'text': p['text'],
            'platform': p['platform'],
            'description': p['description'],
            'categoryId': catRef.id,
            'subcategoryId': subRef.id,
            'categoryName': cat['name'],
            'subcategoryName': sub['name'],
            'createdAt': FieldValue.serverTimestamp(),
          });
        }
        await subRef.update({'promptCount': prompts.length});
        totalPrompts += prompts.length;
        onProgress('  ✅ ${sub['name']} — ${prompts.length} prompts added');
      }
      await catRef.update({'promptCount': totalPrompts});
    }
    onProgress('🎉 ALL DONE! Database seeded successfully!');
  }

